internal suspend fun <T, V> withContextUndispatched(
    newContext: CoroutineContext,
    value: V,
    countOrElement: Any = threadContextElements(newContext), // can be precomputed for speed
    block: suspend (V) -> T
): T =
    suspendCoroutineUninterceptedOrReturn sc@ { uCont ->
        val result = try {
            withCoroutineContext(newContext, countOrElement) {
                block.startCoroutineUninterceptedOrReturn(value, StackFrameContinuation(uCont, newContext))
            }
        } catch (e: DispatchException) {
            // Dispatcher threw an exception (e.g., Dispatchers.Main not available).
            // Resume the continuation with the underlying cause to avoid silent hanging.
            uCont.resumeWithException(e.cause)
            return@sc COROUTINE_SUSPENDED
        }
        result
    }"}

