    fun testCancelledFlowOn() = runTest {
        assertFailsWith<CancellationException> {
            coroutineScope {
                val scope = this
                flow {
                    emit(Unit) // emit to buffer
                    scope.cancel() // now cancel outer scope
                }.flowOn(wrapperDispatcher()).collect {
                    // should not be reached, because cancelled before it runs
                    expectUnreached()
                }
            }
        }
    }

    @Test
    fun testFlowOnWithThrowingDispatcher() = runTest {
        // Create a dispatcher that throws an exception when isDispatchNeeded is called
        val errorMessage = "Dispatcher not available"
        val throwingDispatcher = object : CoroutineDispatcher() {
            override fun isDispatchNeeded(context: CoroutineContext): Boolean {
                throw IllegalStateException(errorMessage)
            }
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw IllegalStateException(errorMessage)
            }
        }

        // Verify that the exception is properly propagated instead of hanging
        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .flowOn(throwingDispatcher)
                .collect {
                    expectUnreached()
                }
        }
        assertEquals(errorMessage, exception.message)
    }
}"}

